import{_ as e,a,b as o,c as r,d}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as i,o as n,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Додавання каналу OneDrive","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/upload/onedrive.md","filePath":"uk-UA/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"uk-UA/upload/onedrive.md"};function p(h,t,m,u,b,f){return n(),s("div",null,[...t[0]||(t[0]=[l('<h1 id="додавання-каналу-onedrive" tabindex="-1">Додавання каналу OneDrive <a class="header-anchor" href="#додавання-каналу-onedrive" aria-label="Permalink to &quot;Додавання каналу OneDrive&quot;">​</a></h1><h2 id="що-підготувати-спочатку" tabindex="-1">Що підготувати спочатку <a class="header-anchor" href="#що-підготувати-спочатку" aria-label="Permalink to &quot;Що підготувати спочатку&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Потрібно</th><th>Навіщо це потрібно</th></tr></thead><tbody><tr><td>Обліковий запис Microsoft</td><td>Для доступу до сторінок адміністрування Microsoft і авторизації OneDrive</td></tr><tr><td>Ваш домен ImgBed</td><td>Для OAuth callback URL</td></tr><tr><td>App registration</td><td>Для отримання <code>Client ID</code> і <code>Client Secret</code></td></tr><tr><td>Обліковий запис OneDrive</td><td>Фактичне місце зберігання файлів</td></tr></tbody></table><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><h3 id="крок-1-відкриите-microsoft-entra-id" tabindex="-1">Крок 1. Відкрийте Microsoft Entra ID <a class="header-anchor" href="#крок-1-відкриите-microsoft-entra-id" aria-label="Permalink to &quot;Крок 1. Відкрийте Microsoft Entra ID&quot;">​</a></h3><ol><li>Відкрийте <code>portal.azure.com</code>.</li><li>Угорі знайдіть <code>Microsoft Entra ID</code>.</li><li>Якщо потрібна сторінка не з&#39;явилася в меню, виберіть:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li>Відкрийте <code>Microsoft Entra ID</code>.</li><li>Відкрийте <code>App registrations</code>.</li><li>Натисніть <code>New registration</code>.</li></ol><h3 id="крок-2-зареєструите-застосунок" tabindex="-1">Крок 2. Зареєструйте застосунок <a class="header-anchor" href="#крок-2-зареєструите-застосунок" aria-label="Permalink to &quot;Крок 2. Зареєструйте застосунок&quot;">​</a></h3><p>На сторінці <code>New registration</code> заповніть:</p><table tabindex="0"><thead><tr><th>Поле</th><th>Що ввести</th></tr></thead><tbody><tr><td>Name</td><td>Зрозуміла назва, наприклад <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Виберіть за таблицею нижче</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Підказка щодо типу акаунтів:</p><table tabindex="0"><thead><tr><th>Ваш сценарій</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>Тільки особистий OneDrive</td><td>Виберіть варіант для personal Microsoft account.</td></tr><tr><td>Особисті та робочі або навчальні акаунти</td><td>Виберіть варіант, який підтримує і personal, і organizational accounts.</td></tr><tr><td>Тільки корпоративний або навчальний OneDrive</td><td>Виберіть варіант для organizational account.</td></tr></tbody></table><p>Після заповнення форми натисніть register.</p><p><img src="'+e+'" alt="Створення OneDrive app" loading="lazy"></p><h3 id="крок-3-скопіюите-дані-застосунку" tabindex="-1">Крок 3. Скопіюйте дані застосунку <a class="header-anchor" href="#крок-3-скопіюите-дані-застосунку" aria-label="Permalink to &quot;Крок 3. Скопіюйте дані застосунку&quot;">​</a></h3><p>Після створення застосунку скопіюйте ці значення зі сторінки overview:</p><table tabindex="0"><thead><tr><th>Поле Microsoft</th><th>Поле ImgBed</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> для organizational accounts</td></tr></tbody></table><p><img src="'+a+'" alt="Application і tenant IDs" loading="lazy"></p><h3 id="крок-4-створіть-client-secret" tabindex="-1">Крок 4. Створіть Client Secret <a class="header-anchor" href="#крок-4-створіть-client-secret" aria-label="Permalink to &quot;Крок 4. Створіть Client Secret&quot;">​</a></h3><ol><li>Відкрийте <code>Certificates &amp; secrets</code>.</li><li>Натисніть <code>New client secret</code>.</li><li>Введіть будь-який зручний опис.</li><li>Виберіть строк дії.</li><li>Одразу після створення скопіюйте <code>Value</code>.</li></ol><p><img src="'+o+'" alt="Збереження значення client secret" loading="lazy"></p><h3 id="крок-5-додаите-api-permissions" tabindex="-1">Крок 5. Додайте API permissions <a class="header-anchor" href="#крок-5-додаите-api-permissions" aria-label="Permalink to &quot;Крок 5. Додайте API permissions&quot;">​</a></h3><ol><li>Відкрийте <code>API permissions</code>.</li><li>Натисніть <code>Add a permission</code>.</li><li>Виберіть <code>Microsoft Graph</code>.</li><li>Виберіть <code>Delegated permissions</code>.</li><li>Додайте такі permissions:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Призначення</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Завантаження файлів, створення папок і видалення файлів</td></tr><tr><td><code>offline_access</code></td><td>Дозволяє ImgBed отримати <code>Refresh Token</code></td></tr><tr><td><code>User.Read</code></td><td>Читання інформації про акаунт і квоту</td></tr></tbody></table><h3 id="крок-6-заповніть-канал-onedrive" tabindex="-1">Крок 6. Заповніть канал OneDrive <a class="header-anchor" href="#крок-6-заповніть-канал-onedrive" aria-label="Permalink to &quot;Крок 6. Заповніть канал OneDrive&quot;">​</a></h3><p>У налаштуваннях завантаження виберіть <code>OneDrive</code> і заповніть:</p><table tabindex="0"><thead><tr><th>Поле ImgBed</th><th>Що ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Зрозуміла назва, наприклад <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>Скопійоване значення <code>Client Secret Value</code></td></tr><tr><td>Tenant ID</td><td>Виберіть за таблицею нижче</td></tr><tr><td>Refresh Token</td><td>Поки залиште порожнім</td></tr><tr><td>Root directory</td><td>Необов&#39;язково. Типово <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Необов&#39;язково</td></tr></tbody></table><p><img src="'+r+'" alt="Заповнення конфігурації OneDrive-каналу" loading="lazy"></p><p>Як заповнити <code>Tenant ID</code>:</p><table tabindex="0"><thead><tr><th>Вибраний тип акаунтів</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Personal accounts</td><td><code>consumers</code></td></tr><tr><td>Personal + organizational accounts</td><td><code>common</code></td></tr><tr><td>Тільки поточна організація</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="крок-7-отримаите-refresh-token" tabindex="-1">Крок 7. Отримайте Refresh Token <a class="header-anchor" href="#крок-7-отримаите-refresh-token" aria-label="Permalink to &quot;Крок 7. Отримайте Refresh Token&quot;">​</a></h3><ol><li>В ImgBed натисніть <code>Get Token</code>.</li><li>Увійдіть у Microsoft-акаунт, який хочете підключити.</li><li>Підтвердьте запит авторизації.</li><li>На callback-сторінці з&#39;явиться <code>Refresh Token</code>.</li><li>Скопіюйте його.</li><li>Поверніться до ImgBed і вставте його в поле <code>Refresh Token</code>.</li></ol><p><img src="'+d+`" alt="Копіювання refresh token" loading="lazy"></p><h3 id="крок-8-збережіть-канал" tabindex="-1">Крок 8. Збережіть канал <a class="header-anchor" href="#крок-8-збережіть-канал" aria-label="Permalink to &quot;Крок 8. Збережіть канал&quot;">​</a></h3><p>Коли всі поля заповнені, збережіть канал.</p><h2 id="короткии-сценаріи" tabindex="-1">Короткий сценарій <a class="header-anchor" href="#короткии-сценаріи" aria-label="Permalink to &quot;Короткий сценарій&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Відкрити portal.azure.com</span></span>
<span class="line"><span>-&gt; Знайти Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; Відкрити App registrations</span></span>
<span class="line"><span>-&gt; Зареєструвати новий app</span></span>
<span class="line"><span>-&gt; Заповнити Name / Supported account types / Web redirect URI</span></span>
<span class="line"><span>-&gt; Зареєструвати</span></span>
<span class="line"><span>-&gt; Скопіювати Application (client) ID</span></span>
<span class="line"><span>-&gt; Перевірити callback URL в Authentication</span></span>
<span class="line"><span>-&gt; Створити Client Secret у Certificates &amp; secrets</span></span>
<span class="line"><span>-&gt; Додати permissions в API permissions</span></span>
<span class="line"><span>-&gt; Ввести Client ID / Client Secret / Tenant ID в ImgBed</span></span>
<span class="line"><span>-&gt; Натиснути Get Token</span></span>
<span class="line"><span>-&gt; Скопіювати Refresh Token з callback-сторінки</span></span>
<span class="line"><span>-&gt; Вставити його назад в ImgBed і зберегти</span></span></code></pre></div><h2 id="посилання" tabindex="-1">Посилання <a class="header-anchor" href="#посилання" aria-label="Permalink to &quot;Посилання&quot;">​</a></h2><ol><li>Microsoft Entra app registration: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const D=i(c,[["render",p]]);export{v as __pageData,D as default};
